import{_ as t,o as e,c as l,a2 as i}from"./chunks/framework.Bkqnpl2X.js";const b=JSON.parse('{"title":"贡献指南","description":"","frontmatter":{},"headers":[],"relativePath":"contributing.md","filePath":"contributing.md","lastUpdated":1780443280000}'),r={name:"contributing.md"};function o(d,a,s,n,h,c){return e(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="贡献指南" tabindex="-1">贡献指南 <a class="header-anchor" href="#贡献指南" aria-label="Permalink to &quot;贡献指南&quot;">​</a></h1><blockquote><p>欢迎加入Avis知识体系的共建！本指南将帮助你了解如何参与贡献。</p></blockquote><hr><h2 id="为什么参与贡献" tabindex="-1">为什么参与贡献？ <a class="header-anchor" href="#为什么参与贡献" aria-label="Permalink to &quot;为什么参与贡献？&quot;">​</a></h2><p>Avis是全球航空航天阀门领域知识体系的&quot;活的大厦&quot;。你的每一次贡献——无论是修正一个错别字、补充一段技术细节，还是撰写一个全新章节——都将让这座大厦更加坚固、完备。</p><hr><h2 id="贡献者角色与权限" tabindex="-1">贡献者角色与权限 <a class="header-anchor" href="#贡献者角色与权限" aria-label="Permalink to &quot;贡献者角色与权限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>参与方式</th><th>典型贡献</th></tr></thead><tbody><tr><td>浏览者</td><td>GitHub Issue</td><td>报告错误、提出改进建议</td></tr><tr><td>贡献者</td><td>Fork → Pull Request</td><td>修正内容、补充章节、翻译</td></tr><tr><td>评审者</td><td>PR Review</td><td>审核技术准确性、格式规范性</td></tr><tr><td>维护者</td><td>Merge + Release</td><td>合并PR、发布版本</td></tr><tr><td>作者</td><td>最终决策</td><td>版本规划、架构设计</td></tr></tbody></table><hr><h2 id="rfc提案流程" tabindex="-1">RFC提案流程 <a class="header-anchor" href="#rfc提案流程" aria-label="Permalink to &quot;RFC提案流程&quot;">​</a></h2><p>Avis采用RFC（Request for Comments）流程管理重大变更：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 提出提案 → 2. 社区讨论 → 3. 核心评审 → 4. 实施合并 → 5. 版本发布</span></span>\n<span class="line"><span>   (2周讨论期)    (公开讨论)     (≥2位评审)    (PR通过)      (Git Tag)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="第一步-创建rfc提案" tabindex="-1">第一步：创建RFC提案 <a class="header-anchor" href="#第一步-创建rfc提案" aria-label="Permalink to &quot;第一步：创建RFC提案&quot;">​</a></h3><p>在 <code>collaboration/proposals/</code> 目录下创建提案文件，使用 <a href="https://github.com/avis-aerospace/avis-web/blob/main/collaboration/templates/rfc-template.md" target="_blank" rel="noreferrer">RFC模板</a>，包含：</p><ul><li><strong>提案标题</strong>：简洁描述改进内容（如 &quot;RFC: 新增第XX章 低温阀门热力学分析&quot;）</li><li><strong>动机与背景</strong>：为什么要做这个改进？解决什么问题？</li><li><strong>详细方案</strong>：具体怎么改？涉及哪些章节？</li><li><strong>影响范围</strong>：对现有内容的影响评估</li><li><strong>参考依据</strong>：引用的标准、文献、工程案例</li></ul><h3 id="第二步-社区讨论" tabindex="-1">第二步：社区讨论 <a class="header-anchor" href="#第二步-社区讨论" aria-label="Permalink to &quot;第二步：社区讨论&quot;">​</a></h3><ul><li>提案提交后，在GitHub Discussions中进行公开讨论</li><li>讨论周期至少2周，确保充分的社区反馈</li><li>提案人需积极回应讨论中的问题</li></ul><h3 id="第三步-核心评审" tabindex="-1">第三步：核心评审 <a class="header-anchor" href="#第三步-核心评审" aria-label="Permalink to &quot;第三步：核心评审&quot;">​</a></h3><ul><li>由核心团队（≥2位评审者）进行技术评审</li><li>评审标准：技术准确性、逻辑一致性、格式规范性、引用完备性</li></ul><h3 id="第四步-实施与合并" tabindex="-1">第四步：实施与合并 <a class="header-anchor" href="#第四步-实施与合并" aria-label="Permalink to &quot;第四步：实施与合并&quot;">​</a></h3><ul><li>评审通过后，贡献者提交Pull Request</li><li>PR需通过自动化检查（Markdown语法、链接有效性）</li><li>维护者确认后合并</li></ul><h3 id="第五步-版本发布" tabindex="-1">第五步：版本发布 <a class="header-anchor" href="#第五步-版本发布" aria-label="Permalink to &quot;第五步：版本发布&quot;">​</a></h3><ul><li>合并后按版本编号规则更新版本号</li><li>更新CHANGELOG.md</li><li>打Git Tag，触发自动部署</li></ul><hr><h2 id="内容编写规范" tabindex="-1">内容编写规范 <a class="header-anchor" href="#内容编写规范" aria-label="Permalink to &quot;内容编写规范&quot;">​</a></h2><h3 id="markdown标准" tabindex="-1">Markdown标准 <a class="header-anchor" href="#markdown标准" aria-label="Permalink to &quot;Markdown标准&quot;">​</a></h3><ul><li>使用 <code>.md</code> 扩展名，UTF-8编码</li><li>章节标题使用 <code>#</code> 到 <code>####</code> 四级标题</li><li>表格使用标准Markdown表格语法</li><li>代码块指定语言：<code>matlab`、</code>python` 等</li></ul><h3 id="引用格式" tabindex="-1">引用格式 <a class="header-anchor" href="#引用格式" aria-label="Permalink to &quot;引用格式&quot;">​</a></h3><ul><li>参考文献使用 <code>[编号]</code> 标注，在章末列出完整信息</li><li>交叉引用使用 <code>[参见第X章]</code> 格式</li><li>标准引用标注标准编号和版本年份</li></ul><h3 id="公式规范" tabindex="-1">公式规范 <a class="header-anchor" href="#公式规范" aria-label="Permalink to &quot;公式规范&quot;">​</a></h3><ul><li>行内公式使用 <code>$...$</code></li><li>块级公式使用 <code>$$...$$</code></li><li>变量使用斜体，单位使用正体</li><li>向量使用粗体 <code>\\mathbf{}</code></li></ul><h3 id="图片规范" tabindex="-1">图片规范 <a class="header-anchor" href="#图片规范" aria-label="Permalink to &quot;图片规范&quot;">​</a></h3><ul><li>图片存放在 <code>images/</code> 目录</li><li>使用相对路径引用</li><li>建议分辨率：宽度800-1200px</li><li>格式：PNG（截图）、SVG（示意图）</li></ul><hr><h2 id="评审标准" tabindex="-1">评审标准 <a class="header-anchor" href="#评审标准" aria-label="Permalink to &quot;评审标准&quot;">​</a></h2><table tabindex="0"><thead><tr><th>评审维度</th><th>标准</th></tr></thead><tbody><tr><td>技术准确性</td><td>公式推导正确、数据有据可查、结论逻辑严谨</td></tr><tr><td>内容完整性</td><td>覆盖章节目标的所有关键点</td></tr><tr><td>结构清晰度</td><td>层次分明、逻辑递进、便于导航</td></tr><tr><td>引用完备性</td><td>关键论断有参考文献支撑</td></tr><tr><td>术语一致性</td><td>与全书术语体系一致</td></tr><tr><td>格式规范性</td><td>符合Markdown编写规范</td></tr></tbody></table><hr><h2 id="版本编号规则" tabindex="-1">版本编号规则 <a class="header-anchor" href="#版本编号规则" aria-label="Permalink to &quot;版本编号规则&quot;">​</a></h2><p>遵循语义化版本 SemVer 2.0：<code>主版本.次版本.修订号</code></p><ul><li><strong>修订号</strong>（V5.0.x）：勘误修正、小改进、格式优化</li><li><strong>次版本</strong>（V5.x.0）：新增章节、重大修订、功能升级</li><li><strong>主版本</strong>（Vx.0.0）：知识体系重构、平台架构升级</li></ul><hr><h2 id="行为准则" tabindex="-1">行为准则 <a class="header-anchor" href="#行为准则" aria-label="Permalink to &quot;行为准则&quot;">​</a></h2><ul><li>尊重所有贡献者的时间和努力</li><li>建设性讨论，对事不对人</li><li>引用来源，尊重知识产权</li><li>保持专业和学术严谨</li></ul><hr><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><ul><li>GitHub Issues：<a href="https://github.com/avis-aerospace/avis-web/issues/new" target="_blank" rel="noreferrer">提交Issue</a></li><li>GitHub Discussions：<a href="https://github.com/avis-aerospace/avis-web/discussions" target="_blank" rel="noreferrer">社区讨论</a></li></ul>',46)])])}const p=t(r,[["render",o]]);export{b as __pageData,p as default};
